package com.example.paymentprocessingmodule

import android.content.Context
import android.os.Bundle
import android.os.Parcelable
import androidx.annotation.RequiresApi
import com.android.billingclient.api.*
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.Job
import kotlinx.coroutines.async
import java.util.ArrayList
import kotlin.coroutines.CoroutineContext

class PaymentProcessingModule(context: Context) : CoroutineScope {
    private val billingClient = BillingClient.newBuilder(context).build()
    private var job: Job? = null

    init {
        job = Job()
    }

    override val coroutineContext: CoroutineContext
        get() = Dispatchers.Main + job!!

    fun purchaseProduct(productId: String, type: BillingClient.SkuType): Job {
        return async {
            val responseCode = billingClient.launchBillingFlow(context, BillingFlowParams.newBuilder().setSku(productId).setType(type).build())
            if (responseCode == BillingClient.BillingResponseCode.OK) {
                println("Successfully launched purchase flow for product $productId")
            } else {
                println("Failed to launch purchase flow for product $productId with response code $responseCode")
            }
        }
    }

    fun queryProducts(productIds: ArrayList<String>, type: BillingClient.SkuType): Job {
        return async {
            val skuDetails = billingClient.querySkuDetails(context, SkuDetailsParams.newBuilder().setSkusList(productIds).setType(type).build())
            if (skuDetails.responseCode == BillingClient.BillingResponseCode.OK) {
                println("Successfully queried product details for products $productIds")
            } else {
                println("Failed to query product details for products $productIds with response code $responseCode")
            }
        }
    }
}